<?php include 'header.php'; require_login(); if(empty($_SESSION['cart'])){header('Location: cart.php'); exit;} $message=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $name=trim($_POST['customer_name']); $email=trim($_POST['email']); $phone=trim($_POST['phone']); $address=trim($_POST['address']); $ids=array_keys($_SESSION['cart']); $ph=implode(',',array_fill(0,count($ids),'?')); $stmt=$pdo->prepare("SELECT * FROM products WHERE id IN ($ph)"); $stmt->execute($ids); $products=$stmt->fetchAll(); $total=0; foreach($products as $pr){$total+=$pr['price']*$_SESSION['cart'][$pr['id']];} $pdo->beginTransaction(); $order=$pdo->prepare('INSERT INTO orders (user_id,customer_name,email,phone,address,total) VALUES (?,?,?,?,?,?)'); $order->execute([$_SESSION['user_id'],$name,$email,$phone,$address,$total]); $oid=$pdo->lastInsertId(); $item=$pdo->prepare('INSERT INTO order_items (order_id,product_id,quantity,price) VALUES (?,?,?,?)'); $stock=$pdo->prepare('UPDATE products SET stock=stock-? WHERE id=?'); foreach($products as $pr){$qty=$_SESSION['cart'][$pr['id']]; $item->execute([$oid,$pr['id'],$qty,$pr['price']]); $stock->execute([$qty,$pr['id']]);} $pdo->commit(); $_SESSION['cart']=[]; $message="Order placed successfully! Your order number is #$oid."; } ?>
<section class="section narrow"><h1>Checkout</h1><?php if($message): ?><div class="success"><?= htmlspecialchars($message); ?></div><?php else: ?><form class="form" method="POST"><input name="customer_name" required placeholder="Full name" value="<?= htmlspecialchars($_SESSION['name']??''); ?>"><input name="email" type="email" required placeholder="Email" value="<?= htmlspecialchars($_SESSION['email']??''); ?>"><input name="phone" required placeholder="Phone number"><textarea name="address" required placeholder="Delivery address"></textarea><button class="btn">Place Order</button></form><?php endif; ?></section><?php include 'footer.php'; ?>
